import { useNavigate, Link } from "react-router-dom";

function Error() {
  const navigate = useNavigate();

  return (
    <div>
      <h1>ERROR 404</h1>
      <h2>
        Esta página no existe, vuelve al 
        <Link to="/" onClick={() => navigate("/")} >
          inicio
        </Link>
        .
      </h2>
    </div>
  );
}

export default Error;
